function rect_pos(x1,y1,x2,y2)--矩形边界定位
    local x,y,n = math.random(x1,x2),math.random(y1,y2),math.random(4)
    if n == 1 then
        x = x1
    elseif n == 2 then
        x = x2
    elseif n == 3 then
        y = y1
    elseif n == 4 then
        y = y2
    end
    return x,y
end

function translate(ass_shape,x_incline,y_incline)--平移绘图
    x_incline = x_incline or 0
    y_incline = y_incline or 0
    local shape = string.gsub(ass_shape,"([-.%d]+) ([-.%d]+)",
    function (x,y)
        x = round(tonumber(x)+x_incline,3)
        y = round(tonumber(y)+y_incline,3)
        return string.format("%s %s",x,y)
    end)
    return shape
end

function zoom(ass_shape,x_zoom,y_zoom,zoom_center,zoom_middle)--缩放绘图
    x_zoom = x_zoom or 100
    y_zoom = y_zoom or x_zoom
    zoom_center = zoom_center or 0
    zoom_middle = zoom_middle or 0
    local shape = string.gsub(ass_shape,"([-.%d]+) ([-.%d]+)",
    function (x,y)
        x = round(zoom_center+(tonumber(x)-zoom_center)*x_zoom/100,3)
        y = round(zoom_middle+(tonumber(y)-zoom_middle)*y_zoom/100,3)
        return string.format("%s %s",x,y)
    end)
    return shape
end

function spin(ass_shape,x_angle,y_angle,z_angle,spin_center,spin_middle)--旋转绘图
    x_angle = x_angle or 0
    y_angle = y_angle or 0
    z_angle = z_angle or 0
    spin_center = spin_center or 0
    spin_middle = spin_middle or 0
    local shape = string.gsub(ass_shape,"([-.%d]+) ([-.%d]+)",
    function (x,y)
        x = spin_center + (tonumber(x)-spin_center)*math.cos(math.rad(y_angle))
        y = spin_middle + (tonumber(y)-spin_middle)*math.cos(math.rad(x_angle))
        local new_x = round(spin_center+(x-spin_center)*math.cos(math.rad(-z_angle))-(y-spin_middle)*math.sin(math.rad(-z_angle)),3)
        local new_y = round(spin_middle+(x-spin_center)*math.sin(math.rad(-z_angle))+(y-spin_middle)*math.cos(math.rad(-z_angle)),3)
        return string.format("%s %s",new_x,new_y)
    end)
    return shape
end

function translate_tbl(ass_table,x_incline,y_incline)--平移绘图表中的每个绘图
    x_incline = x_incline or 0
    y_incline = y_incline or 0
    local ass = {}
    for i = 1,#ass_table do
        local shape = string.gsub(ass_table[i],"([-.%d]+) ([-.%d]+)",
        function (x,y)
            x = round(tonumber(x)+x_incline,3)
            y = round(tonumber(y)+y_incline,3)
            return string.format("%s %s",x,y)
        end)
        ass[#ass+1] = shape
    end
    return ass
end

function zoom_tbl(ass_table,x_zoom,y_zoom,zoom_center,zoom_middle)--缩放绘图表中的每个绘图
    x_zoom = x_zoom or 100
    y_zoom = y_zoom or x_zoom
    zoom_center = zoom_center or 0
    zoom_middle = zoom_middle or 0
    local ass = {}
    for i = 1,#ass_table do
        local shape = string.gsub(ass_table[i],"([-.%d]+) ([-.%d]+)",
        function (x,y)
            x = round(zoom_center+(tonumber(x)-zoom_center)*x_zoom/100,3)
            y = round(zoom_middle+(tonumber(y)-zoom_middle)*y_zoom/100,3)
            return string.format("%s %s",x,y)
        end)
        ass[#ass+1] = shape
    end
    return ass
end

function spin_tbl(ass_table,x_angle,y_angle,z_angle,spin_center,spin_middle)--旋转绘图表中的每个绘图
    x_angle = x_angle or 0
    y_angle = y_angle or 0
    z_angle = z_angle or 0
    spin_center = spin_center or 0
    spin_middle = spin_middle or 0
    local ass = {}
    for i = 1,#ass_table do
        local shape = string.gsub(ass_table[i],"([-.%d]+) ([-.%d]+)",
        function (x,y)
            x = spin_center + (tonumber(x)-spin_center)*math.cos(math.rad(y_angle))
            y = spin_middle + (tonumber(y)-spin_middle)*math.cos(math.rad(x_angle))
            local new_x = round(spin_center+(x-spin_center)*math.cos(math.rad(-z_angle))-(y-spin_middle)*math.sin(math.rad(-z_angle)),3)
            local new_y = round(spin_middle+(x-spin_center)*math.sin(math.rad(-z_angle))+(y-spin_middle)*math.cos(math.rad(-z_angle)),3)
            return string.format("%s %s",new_x,new_y)
        end)
        ass[#ass+1] = shape
    end
    return ass
end

function round_tbl(ass_table,decimal)--给表里的绘图坐标保留指定小数位数
    decimal = decimal or 0
    for i = 1,#ass_table do
        ass_table[i] = string.gsub(ass_table[i],"([-.%d]+) ([-.%d]+)",
        function (x,y)
            x = round(tonumber(x),decimal)
            y = round(tonumber(y),decimal)
            return string.format("%s %s",x,y)
        end)
    end
    return ass_table
end

function ellipse(x_length,y_length,clockwise)--椭圆，可指定路径方向
    clockwise = clockwise or 0
    return zoom(circle(x_length,clockwise),100,y_length/x_length*100)
end

function binary_digit(digit)--生成指定位数的随机二进制数字绘图
    local num = {}
    local O = "m 1 -41 b -39 -42 -38 41 0 40 b 38 41 39 -42 1 -41 m 16 -18 l -18 7 b -20 -43 10 -38 16 -18 m -16 17 l 18 -8 b 23 37 -10 39 -16 17 "
    local I = "m -4 -40 l -29 -27 l -25 -19 l -6 -30 l -6 28 l -26 28 l -26 38 l 23 38 l 23 28 l 5 28 l 5 -40 "
    for i = 1,digit do
        if math.random(1,2) == 1 then
            num[#num+1] = translate(O,70*(i-1))
        else
            num[#num+1] = translate(I,70*(i-1))
        end
    end
    return table.concat(num)
end

function sector(r,s_ang,e_ang,clockwise)--生成扇形
    local function quarter(radius,s_angle,e_angle)
        local angle = e_angle - s_angle
        s_angle,angle,e_angle = math.rad(s_angle-90),math.rad(angle),math.rad(e_angle-90)
        local x0 = math.cos(s_angle)*radius
        local y0 = math.sin(s_angle)*radius
        local x3 = math.cos(e_angle)*radius
        local y3 = math.sin(e_angle)*radius
        local a = math.tan(angle/4)*4/3
        local x1 = x0 - a*y0
        local y1 = y0 + a*x0
        local x2 = x3 + a*y3
        local y2 = y3 - a*x3
        return string.format("b %s %s %s %s %s %s ",round(x1,3),round(y1,3),round(x2,3),round(y2,3),round(x3,3),round(y3,3))
    end
    clockwise = clockwise or 0
    s_ang = s_ang and s_ang*(-1)^clockwise or 0
    e_ang = e_ang and e_ang*(-1)^clockwise or 360
    local ang = (e_ang - s_ang)*(-1)^clockwise
    if 0 < ang and ang <= 90 then
        return "m "..tostring(round(r*math.cos(math.rad(s_ang-90)),3)).." "..tostring(round(r*math.sin(math.rad(s_ang-90)),3)).." "..quarter(r,s_ang,e_ang).."l 0 0 "
    elseif 90 < ang and ang <= 180 then
        return "m "..tostring(round(r*math.cos(math.rad(s_ang-90)),3)).." "..tostring(round(r*math.sin(math.rad(s_ang-90)),3)).." "..quarter(r,s_ang,s_ang+90*(-1)^clockwise)..quarter(r,s_ang+90*(-1)^clockwise,e_ang).."l 0 0 "
    elseif 180 < ang and ang <= 270 then
        return "m "..tostring(round(r*math.cos(math.rad(s_ang-90)),3)).." "..tostring(round(r*math.sin(math.rad(s_ang-90)),3)).." "..quarter(r,s_ang,s_ang+90*(-1)^clockwise)..quarter(r,s_ang+90*(-1)^clockwise,s_ang+180*(-1)^clockwise)..quarter(r,s_ang+180*(-1)^clockwise,e_ang).."l 0 0 "
    elseif 270 < ang and ang < 360 then
        return "m "..tostring(round(r*math.cos(math.rad(s_ang-90)),3)).." "..tostring(round(r*math.sin(math.rad(s_ang-90)),3)).." "..quarter(r,s_ang,s_ang+90*(-1)^clockwise)..quarter(r,s_ang+90*(-1)^clockwise,s_ang+180*(-1)^clockwise)..quarter(r,s_ang+180*(-1)^clockwise,s_ang+270*(-1)^clockwise)..quarter(r,s_ang+270*(-1)^clockwise,e_ang).."l 0 0 "
    elseif ang == 360 then
        return circle(2*r)
    end
end

function clip_blinds(length,height,num,pct,angle,x,y,direction,mode)--生成百叶窗绘图，用于clip效果
    pct = pct < 0 and 0 or pct > 1 and 1 or pct
    angle = angle or 0
    x = x or 0
    y = y or 0
    direction = direction or 0
    mode = mode or 0
    local len = (length^2 + height^2)^0.5
    local wid = len/num
    local ass = {}
    for i = 1,num do
        if direction == 0 then
            ass[#ass+1] = translate(rectangle(wid*pct,len),-len/2 + (i - 1)*wid + wid*pct/2)
        elseif direction == 1 then
            ass[#ass+1] = translate(rectangle(wid*pct,len),-len/2 + (i - 1/2)*wid)
        end
    end
    ass = translate_tbl(spin_tbl(ass,0,0,angle),x,y)
    if mode == 0 then
        return table.concat(ass)
    elseif mode == 1 then
        return ass
    end
end

local function link(length1,length2,clockwise)
    length2 = length2 or length1
    clockwise = clockwise or 0
    local S = "m %.3f %.3f b %.3f %.3f %.3f %.3f %.3f %.3f l %.3f %.3f b %.3f %.3f %.3f %.3f %.3f %.3f "
    local a = length1/2
    local b = length2/2
    if clockwise == 0 then
        return string.format(S,-a,-b,-a,-b-a*4/3,a,-b-a*4/3,a,-b,a,b,a,b+a*4/3,-a,b+a*4/3,-a,b)
    elseif clockwise == 1 then
        return string.format(S,-a,b,-a,b+a*4/3,a,b+a*4/3,a,b,a,-b,a,-b-a*4/3,-a,-b-a*4/3,-a,-b)
    end
end

function chain(num,x_length,y_length,width,first)--生成直线锁链绘图
    x_length = x_length or 30
    y_length = y_length or 20
    width = width or 5
    first = first or 0
    local O = link(x_length,y_length)..link(x_length - width*2,y_length,1)
    local I = link(width,x_length + y_length - width*2)
    local ass = {}
    if first == 0 then
        for i = 1,num do
            if i % 2 == 1 then
                ass[#ass+1] = translate(O,0,(x_length + y_length - width*3)*(i - 1))
            else
                ass[#ass+1] = translate(I,0,(x_length + y_length - width*3)*(i - 1))
            end
        end
    elseif first == 1 then
        for i = 1,num do
            if i % 2 == 1 then
                ass[#ass+1] = translate(I,0,(x_length + y_length - width*3)*(i - 1))
            else
                ass[#ass+1] = translate(O,0,(x_length + y_length - width*3)*(i - 1))
            end
        end
    end
    return table.concat(ass)
end

function chains_entwined(tbl,xscale,x_length,y_length,width,first,tbl2)--做锁链缠绕效果
    xscale = xscale or 1
    x_length = x_length or 30
    y_length = y_length or 20
    width = width or 5
    first = first or 0
    local O = link(x_length,y_length)..link(x_length - width*2,y_length,1)
    local I = link(width,x_length + y_length - width*2)
    local ass1 = {}
    local ass2 = {}
    if first == 0 then
        for i = 1,#tbl do
            if i % 2 == 1 then
                if math.cos(math.rad(tbl[i].x/xscale)) >= 0 then
                    ass1[#ass1+1] = translate(spin(O,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                else
                    ass2[#ass2+1] = translate(spin(O,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                end
            else
                if math.cos(math.rad(tbl[i].x/xscale)) >= 0 then
                    ass1[#ass1+1] = translate(spin(I,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                else
                    ass2[#ass2+1] = translate(spin(I,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                end
            end
        end
    elseif first == 1 then
        for i = 1,#tbl do
            if i % 2 == 1 then
                if math.cos(math.rad(tbl[i].x/xscale)) >= 0 then
                    ass1[#ass1+1] = translate(spin(I,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                else
                    ass2[#ass2+1] = translate(spin(I,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                end
            else
                if math.cos(math.rad(tbl[i].x/xscale)) >= 0 then
                    ass1[#ass1+1] = translate(spin(O,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                else
                    ass2[#ass2+1] = translate(spin(O,0,0,tbl[i].angle-90),tbl[i].x,tbl[i].y)
                end
            end
        end
    end
    if tbl2 then
        if first == 0 then
            for i = 1,#tbl2 do
                if i % 2 == 1 then
                    if -math.cos(math.rad(tbl2[i].x/xscale)) >= 0 then
                        ass1[#ass1+1] = translate(spin(O,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    else
                        ass2[#ass2+1] = translate(spin(O,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    end
                else
                    if -math.cos(math.rad(tbl2[i].x/xscale)) >= 0 then
                        ass1[#ass1+1] = translate(spin(I,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    else
                        ass2[#ass2+1] = translate(spin(I,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    end
                end
            end
        elseif first == 1 then
            for i = 1,#tbl2 do
                if i % 2 == 1 then
                    if -math.cos(math.rad(tbl2[i].x/xscale)) >= 0 then
                        ass1[#ass1+1] = translate(spin(I,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    else
                        ass2[#ass2+1] = translate(spin(I,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    end
                else
                    if -math.cos(math.rad(tbl2[i].x/xscale)) >= 0 then
                        ass1[#ass1+1] = translate(spin(O,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    else
                        ass2[#ass2+1] = translate(spin(O,0,0,tbl2[i].angle-90),tbl2[i].x,tbl2[i].y)
                    end
                end
            end
        end
    end
    return {table.concat(ass1),table.concat(ass2)}
end

function disassemble(ass_shape)--拆解单m绘图
    local ass = {}
    for m in string.gmatch(ass_shape,"m[^m]+") do
        ass[#ass+1] = string.match(m,"(m[^m]+)")
    end
    return ass
end

function ring(ass_shape,n)--旋转绘图并连接
    local ass = {ass_shape}
    for i = 2,n do
        ass[#ass+1] = spin(ass_shape,0,0,(i-1)*360/n)
    end
    return table.concat(ass)
end

function reverse_tbl(tbl)--反转表中元素顺序
    local res = {}
    for i = #tbl,1,-1 do
        res[#res+1] = tbl[i]
    end
    return res
end

function shuffle(tbl)--打乱表中元素顺序
    for i = #tbl,2,-1 do
        local j = math.random(i)
        tbl[i],tbl[j] = tbl[j],tbl[i]
    end
    return tbl
end

function part(tbl,level,mode)--随机显示表中一部分比例的绘图
    level = level < 0 and 0 or level > 1 and 1 or level
    mode = mode or 0
    local result = {}
    for i = #tbl,2,-1 do
        local j = math.random(i)
        tbl[i],tbl[j] = tbl[j],tbl[i]
    end
    for i = 1,math.ceil(#tbl*level) do
        result[i] = tbl[i]
    end
    if mode == 0 then
        return table.concat(result)
    elseif mode == 1 then
        return result
    end
end

function overturn(ass_shape,line_number,x_incline,line,y_incline)--做密铺正六边形和菱形翻转效果
    local tem = {}
    local ass = {}
    for i = 1,2*line_number do
        ass[i] = {}
        ass[i].x = round((x_incline/2)*(i-1),3)
        ass[i].y = ((i+1)%2)*y_incline
    end
    for i = 1,math.ceil(line/2) do
        tem[#tem+1] = translate(ass_shape,0,2*(i-1)*y_incline)
    end
    ass.s = table.concat(tem)
    return ass
end

function arrange(ass_shape,line_number,x_incline,line,y_incline,first_proportion,last_proportion,line_x_incline,mode)
--生成规律排列的绘图  参数:图形,单行个数,x偏移量,总行数,y偏移量,第一行缩放比例,最后一行缩放比例,偶数行初始x偏移量,模式
    line = line or 1
    y_incline = y_incline or x_incline
    first_proportion = first_proportion or 100
    last_proportion = last_proportion or first_proportion
    line_x_incline = line_x_incline or 0
    mode = mode or 0
    local z = (last_proportion - first_proportion)/(line - 1)
    local ass = {}
    if line == 1 then
        for j = 1,line_number do
            ass[#ass+1] = translate(ass_shape,x_incline*(j - 1),0)
        end
    else
        for i = 1,line do
            if i % 2 == 1 then
                for j = 1,line_number do
                    ass[#ass+1] = translate(zoom(ass_shape,first_proportion + z*(i - 1)),x_incline*(j - 1),y_incline*(i - 1))
                end
            else
                for j = 1,line_number do
                    ass[#ass+1] = translate(zoom(ass_shape,first_proportion + z*(i - 1)),x_incline*(j - 1) + line_x_incline,y_incline*(i - 1))
                end
            end
        end
    end
    if mode == 0 then
        return table.concat(ass)
    elseif mode == 1 then
        return ass
    end
end

function tessellation(ass_shape,line_number,x_incline,line,y_incline,line_x_incline,first_overturn,adjacent_overturn,adjacent_y_incline,mode)
--[[生成密铺状态的可密铺图形
    参数:图形,单行个数,x偏移量,总行数,y偏移量,偶数行初始x偏移量,偶数行第一个图形翻转状态,每行相邻两个图形的翻转状态,每行相邻两个图形的y偏移量,模式]]
    line_x_incline = line_x_incline or 0
    first_overturn = first_overturn or 2
    adjacent_overturn = adjacent_overturn or 1
    adjacent_y_incline = adjacent_y_incline or 0
    mode = mode or 0
    local ass = {}
    for i = 1,line do
        if i % 2 == 1 then
            for j = 1,line_number do
                if j % 2 == 1 then
                    local shape = string.gsub(ass_shape,"([-.%d]+) ([-.%d]+)",
                    function (x,y)
                        x = round(tonumber(x) + (j-1)*x_incline,3)
                        y = round(tonumber(y) + (i-1)*y_incline,3)
                        return string.format("%s %s",x,y)
                    end)
                    ass[#ass+1] = shape
                else
                    local shape = string.gsub(ass_shape,"([-.%d]+) ([-.%d]+)",
                    function (x,y)
                        x = round(tonumber(x) + (j-1)*x_incline,3)
                        if adjacent_overturn == 0 then
                            y = round(-(tonumber(y) - (i-1)*y_incline + adjacent_y_incline),3)
                        elseif adjacent_overturn == 1 then
                            y = round(tonumber(y) + (i-1)*y_incline,3)
                        end
                        return string.format("%s %s",x,y)
                    end)
                    ass[#ass+1] = shape
                end
            end
        else
            for k = 1,line_number do
                if k % 2 == 1 then
                    local shape = string.gsub(ass_shape,"([-.%d]+) ([-.%d]+)",
                    function (x,y)
                        if first_overturn == 0 then
                            x = round(-(tonumber(x) - (k-1)*x_incline - line_x_incline),3)
                            y = round(tonumber(y) + (i-1)*y_incline,3)
                        elseif first_overturn == 1 then
                            x = round(tonumber(x) + (k-1)*x_incline + line_x_incline,3)
                            y = round(-(tonumber(y) - (i-1)*y_incline + adjacent_y_incline),3)
                        elseif first_overturn == 2 then
                            x = round(tonumber(x) + (k-1)*x_incline + line_x_incline,3)
                            y = round(tonumber(y) + (i-1)*y_incline,3)
                        end
                        return string.format("%s %s",x,y)
                    end)
                    ass[#ass+1] = shape
                else
                    local shape = string.gsub(ass_shape,"([-.%d]+) ([-.%d]+)",
                    function (x,y)
                        if adjacent_overturn == 1 and first_overturn == 0 then
                            x = round(-(tonumber(x) - (k-1)*x_incline - line_x_incline),3)
                            y = round(tonumber(y) + (i-1)*y_incline,3)
                        elseif adjacent_overturn == 1 and first_overturn == 1 then
                            x = round(tonumber(x) + (k-1)*x_incline + line_x_incline,3)
                            y = round(-(tonumber(y) - (i-1)*y_incline + adjacent_y_incline),3)
                        elseif adjacent_overturn == 1 and first_overturn == 2 then
                            x = round(tonumber(x) + (k-1)*x_incline + line_x_incline,3)
                            y = round(tonumber(y) + (i-1)*y_incline,3)
                        elseif adjacent_overturn == 0 and first_overturn == 1 then
                            x = round(tonumber(x) + (k-1)*x_incline + line_x_incline,3)
                            y = round(tonumber(y) + (i-1)*y_incline,3)
                        end
                        return string.format("%s %s",x,y)
                    end)
                    ass[#ass+1] = shape
                end
            end
        end
    end
    if mode == 0 then
        return table.concat(ass)
    elseif mode == 1 then
        return ass
    end
end

function FOT_DotMincho12_Std_M(shape,width,height,stairs)--返回字体所有可能的像素点坐标表和零矩阵
    local function fullhalf_parity(ass_shape,wid,hei)
        local xmin,xmax = math.huge,-math.huge
        local _ = string.gsub(ass_shape,"([-.%d]+) [-.%d]+",
        function (x)
            xmin,xmax = math.min(xmin,x),math.max(xmax,x)
        end)
        local full = xmax > hei/2
        local odd = round((xmax-xmin)/wid*(full and 12 or 6))%2 ~= 0
        return full,odd
    end
    stairs = stairs or 0
    local res,matrix = {},{}
    local full,odd = fullhalf_parity(shape,width,height)
    local rho1,rho2 = parallelogram(height/6/3^0.5,height/12,height/24/3^0.5),parallelogram(height/6/3^0.5,height/12,height/24/3^0.5,0)
    for i = 1,11 do
        matrix[i] = {}
        if full then
            if odd then
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,11 do
                            res[#res+1] = {x = round(j*width/12,3),y = round(i*height/12,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,11 do
                            res[#res+1] = {x = round(j*width/12,3),y = round(i*height/12,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,11 do
                        res[#res+1] = {x = round(j*width/12,3),y = round(i*height/12,3)}
                        matrix[i][j] = 0
                    end
                end
            else
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,10 do
                            res[#res+1] = {x = round(j*width/12 + width/24,3),y = round(i*height/12,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,10 do
                            res[#res+1] = {x = round(j*width/12 + width/24,3),y = round(i*height/12,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,10 do
                        res[#res+1] = {x = round(j*width/12 + width/24,3),y = round(i*height/12,3)}
                        matrix[i][j] = 0
                    end
                end
            end
        else
            if odd then
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,5 do
                            res[#res+1] = {x = round(j*width/6,3),y = round(i*height/12,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,5 do
                            res[#res+1] = {x = round(j*width/6,3),y = round(i*height/12,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,5 do
                        res[#res+1] = {x = round(j*width/6,3),y = round(i*height/12,3)}
                        matrix[i][j] = 0
                    end
                end
            else
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,6 do
                            res[#res+1] = {x = round(j*width/6 - width/12,3),y = round(i*height/12,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,6 do
                            res[#res+1] = {x = round(j*width/6 - width/12,3),y = round(i*height/12,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,6 do
                        res[#res+1] = {x = round(j*width/6 - width/12,3),y = round(i*height/12,3)}
                        matrix[i][j] = 0
                    end
                end
            end
        end
    end
    return res,matrix
end

function Zpix(shape,width,height,stairs)--返回字体所有可能的像素点坐标表和零矩阵
    local function fullhalf_parity(ass_shape,wid,hei)
        local xmin,xmax = math.huge,-math.huge
        local _ = string.gsub(ass_shape,"([-.%d]+) [-.%d]+",
        function (x)
            xmin,xmax = math.min(xmin,x),math.max(xmax,x)
        end)
        local full = round(xmax) > hei*0.55
        local odd = round((xmax-xmin)/wid*(full and 12 or 6))%2 ~= 0
        return full,odd
    end
    stairs = stairs or 0
    local res,matrix = {},{}
    local full,odd = fullhalf_parity(shape,width,height)
    local rho1,rho2 = parallelogram(height/6/3^0.5,height/12,height/24/3^0.5),parallelogram(height/6/3^0.5,height/12,height/24/3^0.5,0)
    for i = 1,11 do
        matrix[i] = {}
        if full then
            if odd then
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,11 do
                            res[#res+1] = {x = round(j*width/12 + width/24,3),y = round(i*height/12 - width/24,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,11 do
                            res[#res+1] = {x = round(j*width/12 + width/24,3),y = round(i*height/12 - width/24,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,11 do
                        res[#res+1] = {x = round(j*width/12 + width/24,3),y = round(i*height/12 - width/24,3)}
                        matrix[i][j] = 0
                    end
                end
            else
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,10 do
                            res[#res+1] = {x = round((j+1)*width/12,3),y = round(i*height/12 - height/24,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,10 do
                            res[#res+1] = {x = round((j+1)*width/12,3),y = round(i*height/12 - height/24,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,10 do
                        res[#res+1] = {x = round((j+1)*width/12,3),y = round(i*height/12 - height/24,3)}
                        matrix[i][j] = 0
                    end
                end
            end
        else
            if odd then
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,5 do
                            res[#res+1] = {x = round(j*width/6 + width/12,3),y = round(i*height/12 - height/24,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,5 do
                            res[#res+1] = {x = round(j*width/6 + width/12,3),y = round(i*height/12 - height/24,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,5 do
                        res[#res+1] = {x = round(j*width/6 + width/12,3),y = round(i*height/12 - height/24,3)}
                        matrix[i][j] = 0
                    end
                end
            else
                if stairs == 1 then
                    if i % 2 == 1 then
                        for j = 1,4 do
                            res[#res+1] = {x = round((j+1)*width/6,3),y = round(i*height/12 - height/24,3),c = "&HFFFFFF&",s = rho1}
                            matrix[i][j] = 0
                        end
                    else
                        for j = 1,4 do
                            res[#res+1] = {x = round((j+1)*width/6,3),y = round(i*height/12 - height/24,3),c = "&H808080&",s = rho2}
                            matrix[i][j] = 0
                        end
                    end
                else
                    for j = 1,4 do
                        res[#res+1] = {x = round((j+1)*width/6,3),y = round(i*height/12 - height/24,3)}
                        matrix[i][j] = 0
                    end
                end
            end
        end
    end
    return res,matrix
end

function pt_in_str_l_shape(ass_shape,pt_x,pt_y)--判断点是否包含在全直线绘图内
    local function sgn(n)
        return n > 0 and 1 or (n < 0 and -1 or 0)
    end
    local function line_isect(x1,y1,x2,y2,y)
        local top,bottom = math.min(y1,y2),math.max(y1,y2)
        if y >= top and y < bottom and bottom - top > 1e-4 then
            return x1 + ((x2-x1)/(y2-y1))*(y-y1)
        end
    end
    local cnt = 0
    for m in string.gmatch(ass_shape,"m[^m]+") do
        local pt = {}
        for x,y in string.gmatch(m,"([-.%d]+) ([-.%d]+)") do
            pt[#pt+1] = {x,y}
        end
        if pt[1][1] ~= pt[#pt][1] or pt[1][2] ~= pt[#pt][2] then
            pt[#pt+1] = {pt[1][1],pt[1][2]}
        end
        for i = 1,#pt-1 do
            local x = line_isect(pt[i][1],pt[i][2],pt[i+1][1],pt[i+1][2],pt_y)
            if x then
                if x <= pt_x then
                    cnt = cnt + sgn(pt[i+1][2]-pt[i][2])
                end
            end
        end
    end
    return cnt ~= 0
end

function tbl_pt_in_str_l_shape(ass_shape,tbl,matrix)--移除表中不包含在全直线绘图内的点并返回结果和二值矩阵
    if matrix then
        for i = #tbl,1,-1 do
            if not pt_in_str_l_shape(ass_shape,tbl[i].x,tbl[i].y) then
                table.remove(tbl,i)
            else
                matrix[math.ceil(i / #matrix[1])][(i-1) % #matrix[1] + 1] = 1
            end
        end
    else
        for i = #tbl,1,-1 do
            if not pt_in_str_l_shape(ass_shape,tbl[i].x,tbl[i].y) then
                table.remove(tbl,i)
            end
        end
    end
    return tbl,matrix
end

function plies(matrix)--根据二值矩阵计算每个像素点下有几个空位
    local cnt,res = {},{}
    for i = 1,#matrix[1] do
        cnt[i] = 0
    end
    for i = #matrix,1,-1 do
        for j = #matrix[i],1,-1 do
            if matrix[i][j] == 1 then
                table.insert(res,1,cnt[j])
            else
                cnt[j] = cnt[j] + 1
            end
        end
    end
    return res
end

function isolated_point(matrix)--根据二值矩阵判断孤立像素点并返回索引表
    local res = {}
    local cnt = 0
    for i = 1,#matrix do
        local up = i > 1 and matrix[i-1]
        local down = i < #matrix and matrix[i+1]
        for j = 1,#matrix[i] do
            if matrix[i][j] == 1 then
                cnt = cnt + 1
                if not ((j > 1 and matrix[i][j-1] == 1) or (j < #matrix[1] and matrix[i][j+1] == 1) or (up and up[j] == 1) or (down and down[j] == 1)) then
                    res[#res+1] = cnt
                end
            end
        end
    end
    return res
end

function blob(matrix)--查找二值矩阵的连通域
    local visited,id,components = {},{},{}
    local cnt = 0
    for i = 1,#matrix do
        visited[i],id[i] = {},{}
        for j = 1,#matrix[i] do
            if matrix[i][j] == 1 then
                cnt = cnt + 1
                id[i][j] = cnt
            end
        end
    end
    for i = 1,#matrix do
        for j = 1,#matrix[i] do
            if matrix[i][j] == 1 and not visited[i][j] then
                local indices = {id[i][j]}
                local queue = {{i,j}}
                visited[i][j] = true
                while #queue > 0 do
                    local current = table.remove(queue,1)
                    local ci,cj = current[1],current[2]
                    for _,dir in ipairs({{0,1},{1,0},{0,-1},{-1,0}}) do
                        local ni,nj = ci + dir[1],cj + dir[2]
                        if ni >= 1 and ni <= #matrix and nj >= 1 and nj <= #matrix[i] then
                            if matrix[ni][nj] == 1 and not visited[ni][nj] then
                                visited[ni][nj] = true
                                table.insert(queue,{ni,nj})
                                table.insert(indices,id[ni][nj])
                            end
                        end
                    end
                end
                table.insert(components,indices)
            end
        end
    end
    return components
end

function num_in_tbl(tbl,num)--查找给定数字是否在表中
    for i = 1,#tbl do
        if tbl[i] == num then
            return true
        end
    end
    return false
end

function num_in_nested(tbl,num)--查找给定数字在嵌套表的第几个表里
    for i = 1,#tbl do
        for j = 1,#tbl[i] do
            if tbl[i][j] == num then
                return i
            end
        end
    end
    return nil
end

function close(ass_shape)--封闭绘图
    local res = {}
    if not string.find(ass_shape," $") then--如果绘图末尾没有半角空格就加一个
        ass_shape = ass_shape.." "
    end
    for m in string.gmatch(ass_shape,"m[^m]+") do--对每个单m绘图进行操作
        local start_point = string.match(m,"^m ([-.%d]+ [-.%d]+)")
        local end_point = string.match(m,"([-.%d]+ [-.%d]+) $")
        if start_point == end_point then
            res[#res+1] = m
        else
            res[#res+1] = m.."l "..start_point.." "
        end
    end
    return table.concat(res)
end

function topmost(ass_shape)--求全直线绘图的所有最顶端的点
    local function standardize_l(shape)--标准化全直线绘图
        local res = {}
        for m in string.gmatch(shape,"m[^m]+") do
            for l in string.gmatch(m,"[ml][- .%d]+") do--匹配所有ml命令段
                if string.match(l,"[ml]") == "m" then
                    res[#res+1] = l
                elseif string.match(l,"[ml]") == "l" then
                    local l_tbl = {}
                    for pt in string.gmatch(l,"[-.%d]+ [-.%d]+") do--每个坐标对间加l命令
                        l_tbl[#l_tbl+1] = "l "..pt.." "
                    end
                    res[#res+1] = table.concat(l_tbl)
                end
            end
        end
        return table.concat(res)
    end
    local function get_line(shape)--求全直线绘图的每条线段顶点坐标
        local cur,res = {},{}
        for seg in string.gmatch(shape,"[ml][^ml]+") do
            local cmd = string.match(seg,"^([ml])")
            local pt = {}
            for num in string.gmatch(seg,"[-.%d]+") do--提取所有坐标
                pt[#pt+1] = tonumber(num)
            end
            if cmd == "m" then
                if #cur >= 4 then--先处理上一条路径
                    for i = 1,#cur-3,2 do
                        table.insert(res,{cur[i],cur[i+1],cur[i+2],cur[i+3]})
                    end
                end
                cur = pt
            elseif cmd == "l" then--延续当前路径
                for _,num in ipairs(pt) do
                    cur[#cur+1] = num
                end
            end
        end
        if #cur >= 4 then--处理最后一条路径
            for i = 1,#cur-3,2 do
                table.insert(res,{cur[i],cur[i+1],cur[i+2],cur[i+3]})
            end
        end
        return res
    end
    local function bounding_x(shape)--求绘图所有坐标中x的最小值和最大值
        local xmin,xmax = math.huge,-math.huge
        local _ = string.gsub(shape,"([-.%d]+) [-.%d]+",
        function (x)
            xmin,xmax = math.min(xmin,x),math.max(xmax,x)--每次替换都会刷新最值
            return ""
        end)
        return xmin,xmax
    end
    local function intersection_point(x1,y1,x2,y2,num)--求与y轴平行的直线与线段的交点
        if (x1 <= num and x2 >= num) or (x1 >= num and x2 <= num) then
            if math.abs(x1 - x2) < 1e-10 then
                if math.abs(x1 - num) < 1e-10 then
                    return {x = num,y = math.min(y1,y2)}--如果重合，要y值小的那个端点
                else
                    return nil
                end
            else
                local t = (num - x1)/(x2 - x1)
                if t >= 0 and t <= 1 then
                    local y = y1 + t*(y2 - y1)
                    return {x = num,y = round(y,3)}
                else
                    return nil
                end
            end
        else
            return nil
        end
    end
    ass_shape = close(standardize_l(ass_shape))
    local res = {}
    local ass = get_line(ass_shape)
    local xmin,xmax = bounding_x(ass_shape)
    for i = math.ceil(xmin),math.floor(xmax) do
        local tem = {}
        for j = 1,#ass do
            local a = intersection_point(ass[j][1],ass[j][2],ass[j][3],ass[j][4],i)
            if a then--先判断是否有交点，避免出现空洞
                tem[#tem+1] = a
            end
        end
        if #tem >= 2 then
            table.sort(tem,function(a,b)--按y值由小到大进行排序
                return a.y < b.y
            end)
        end
        if tem[1] then
            res[#res+1] = tem[1]
        end
    end
    return res
end
